        "artifact_kind": "feature",
        "depends_on": ["feat-notification-settings"]
    },
]

# Compute input snapshot digest
snapshot_payload = json.dumps({"nodes": preview_nodes}, sort_keys=True, separators=(",", ":"))
snapshot_digest = hashlib.sha256(snapshot_payload.encode()).hexdigest()
print(f"INPUT SNAPSHOT DIGEST: sha256:{snapshot_digest}")

# --- CHECK 1: No task-granularity (phase task) nodes ---
VALID_MACRO_KINDS = {"feature", "architecture"}
PHASE_IDS_PATTERN = __import__("re").compile(r"^P(0[1-9]|1[0-3])$")

print("\n--- CHECK 1: Macro-only kinds (no P01..P13 phase tasks) ---")
check1_fail = False
for node in preview_nodes:
    kind = node["artifact_kind"]
    nid = node["graph_node_id"]
    if kind not in VALID_MACRO_KINDS:
        print(f"  FAIL: node '{nid}' has artifact_kind='{kind}', which is NOT a macro kind")
        check1_fail = True
    if PHASE_IDS_PATTERN.match(nid):
        print(f"  FAIL: node id '{nid}' matches P01..P13 phase naming, indicating micro-layer bleed-in")
        check1_fail = True
if not check1_fail:
    print("  PASS: all 4 nodes are artifact_kind in {architecture, feature}; no P01..P13 ids found")

# --- CHECK 2: All depends_on references point to valid nodes ---
print("\n--- CHECK 2: depends_on referential integrity ---")
node_id_set = {n["graph_node_id"] for n in preview_nodes}
check2_fail = False
for node in preview_nodes:
    for dep in node["depends_on"]:
        if dep not in node_id_set:
            print(f"  FAIL: node '{node['graph_node_id']}' depends_on '{dep}' which does NOT exist in graph")
            check2_fail = True
        else:
            print(f"  OK:   node '{node['graph_node_id']}' -> '{dep}' resolves within graph")
if not check2_fail:
    print("  PASS: all depends_on references resolve to existing nodes")

# --- CHECK 3: DAG acyclicity (Kahn's algorithm) ---
print("\n--- CHECK 3: DAG acyclicity ---")
from collections import defaultdict, deque

in_degree = {n["graph_node_id"]: 0 for n in preview_nodes}
adj = defaultdict(list)
for node in preview_nodes:
    for dep in node["depends_on"]:
        if dep in in_degree:
            in_degree[node["graph_node_id"]] += 1
            adj[dep].append(node["graph_node_id"])

queue = deque(nid for nid, deg in in_degree.items() if deg == 0)
visited_order = []
while queue:
    nid = queue.popleft()
    visited_order.append(nid)
    for successor in adj[nid]:
        in_degree[successor] -= 1
        if in_degree[successor] == 0:
            queue.append(successor)

cycle_nodes = [nid for nid, deg in in_degree.items() if deg > 0]
if cycle_nodes:
    print(f"  FAIL: cycle detected involving nodes: {cycle_nodes}")
else:
    print(f"  PASS: graph is acyclic; topological order: {visited_order}")

# --- CHECK 4: No orphan nodes ---
print("\n--- CHECK 4: No orphan nodes ---")
# A node is orphan if it has no dependents AND has no depends_on,
# BUT is also not reachable from any root via the reverse graph.
# Per definition in prompt: "every node is either a root or referenced"
# root = no depends_on; referenced = appears in some node's depends_on
referenced_as_dep = set()
for node in preview_nodes:
    for dep in node["depends_on"]:
        referenced_as_dep.add(dep)

roots = [n["graph_node_id"] for n in preview_nodes if not n["depends_on"]]
orphans = []
for node in preview_nodes:
    nid = node["graph_node_id"]
    is_root = (nid in [n["graph_node_id"] for n in preview_nodes if not n["depends_on"]])
    is_referenced = nid in referenced_as_dep
    if not is_root and not is_referenced:
        orphans.append(nid)

print(f"  Root nodes (no depends_on): {roots}")
print(f"  Referenced as dependency:   {sorted(referenced_as_dep)}")
if orphans:
    print(f"  FAIL: orphan nodes detected (neither root nor referenced): {orphans}")
else:
    print(f"  PASS: no orphan nodes; all nodes are roots or referenced")

# --- Summary ---
print("\n--- OVERALL ---")
all_pass = not check1_fail and not check2_fail and not cycle_nodes and not orphans
print(f"  VERDICT: {'PASS' if all_pass else 'FAIL'}")
print(f"  SNAPSHOT DIGEST: sha256:{snapshot_digest}")
